// Merge del banco AMPLIADO (EXTRA) dentro de KEYWORDS, deduplicado por frase.
// Así cada idioma queda con su set base + ~350 frases nuevas, sin repetidos.
for (const lang of Object.keys(EXTRA)) {
  const base = KEYWORDS[lang] || (KEYWORDS[lang] = []);
  const seen = new Set(base.map(k => k.toLowerCase()));
  for (const kw of EXTRA[lang]) {
    const key = (kw || "").toLowerCase();
    if (!key || seen.has(key)) continue;
    seen.add(key);
    base.push(kw);
  }
}

// Mezcla aleatoria (Fisher-Yates) para rotación en cada carga
function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

export function getKeywords(lang = "", search = "") {
  let items = [];
  if (lang && KEYWORDS[lang]) {
    items = shuffle(KEYWORDS[lang]).map(kw => ({ kw, lang }));
  } else {
    // Mezcla inter-idiomas: toma bloques aleatorios de cada idioma
    items = shuffle(
      Object.entries(KEYWORDS).flatMap(([l, kws]) => shuffle(kws).map(kw => ({ kw, lang: l })))
    );
  }
  if (search) {
    const q = search.toLowerCase();
    items = items.filter(k => k.kw.toLowerCase().includes(q));
  }
  return items;
}

